code = """import json
import re

# Load business data
businesses = var_functions.query_db:60

# Find all WiFi-enabled businesses and extract states
wifi_businesses = []
state_data = {}

for biz in businesses:
    attrs = biz.get('attributes', {})
    if attrs == 'None' or not isinstance(attrs, dict):
        continue
    
    wifi = attrs.get('WiFi', '')
    if wifi and 'no' not in str(wifi).lower():
        business_id = biz.get('business_id', '')
        description = biz.get('description', '')
        
        # Extract state using regex
        state_match = re.search(r'\bin ([A-Z]{2}),', description)
        if state_match:
            state = state_match.group(1)
            wifi_businesses.append({
                'business_id': business_id,
                'state': state,
                'wifi_value': str(wifi)
            })
            state_data[state] = state_data.get(state, 0) + 1

# Find top state
if state_data:
    top_state = max(state_data.items(), key=lambda x: x[1])
else:
    top_state = (None, 0)

print('Total WiFi businesses:', len(wifi_businesses))
print('States with WiFi businesses:', state_data)
print('Top state:', top_state[0], 'with', top_state[1], 'businesses')

# Prepare for next step - get reviews for top state's WiFi businesses
top_state_name = top_state[0]
if top_state_name:
    top_state_business_ids = [b['business_id'] for b in wifi_businesses if b['state'] == top_state_name]
    print('WiFi business IDs for top state sample:', top_state_business_ids[:5])

result = {
    'wifi_businesses_total': len(wifi_businesses),
    'state_distribution': state_data,
    'top_state': top_state[0],
    'top_state_count': top_state[1],
    'top_state_business_ids': top_state_business_ids if top_state_name else []
}

print('__RESULT__:')
print(json.dumps(result))"""

